#include <string>
#include <vector>

using namespace std;

long long solve(std::string s) {
    int n = s.size();
    vector<int> l(n + 1, 0);
    vector<int> c(n + 1, 0);
    vector<int> t(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        l[i+1] = l[i] + (s[i] == 'L');
    }

    for (int i = n - 1; i >= 0; --i) {
        t[i] = t[i+1] + (s[i] == 'T');
    }

    for (int i = n - 1; i >= 0; --i) {
        c[i] = c[i+1] + (s[i] == 'C' ? t[i+1] : 0);
    }

    long long original = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'L') {
            original += c[i+1];
        }
    }

    long long max_add = 0;

    // Case 1: insert 'L' at position i
    for (int i = 0; i <= n; ++i) {
        long long current_l = l[i];
        long long current_c = 0;
        if (i < n) {
            current_c = c[i];
        } else {
            current_c = c[0];
        }
        max_add = max(max_add, current_l * current_c);
    }

    // Case 2: insert 'C' at position i
    for (int i = 0; i <= n; ++i) {
        long long current_l = l[i];
        long long current_t = 0;
        if (i < n) {
            current_t = t[i];
        } else {
            current_t = 0;
        }
        max_add = max(max_add, current_l * current_t);
    }

    // Case 3: insert 'T' at position i
    for (int i = 0; i <= n; ++i) {
        long long current_lc = 0;
        for (int j = 0; j < i; ++j) {
            if (s[j] == 'L') {
                for (int k = i; k < n; ++k) {
                    if (s[k] == 'C') {
                        current_lc++;
                    }
                }
            }
        }
        max_add = max(max_add, current_lc);
    }

    return original + max_add;
}

